    self._nextRefId = 0            --英雄转换refId
    self._isResonance = 0        --是否共鸣
    self._constIsResonance = 0
    self._isLimitTime = 0        --是否为限时英雄
    self._isFuse = 0            -- 是否可融合,客户端运算
    self._upStar = 0            -- 升星字段，添加判断
    self._status = false        -- 状态 1为有状态，0为无状态
    self._battle = false
    self._icon = ""
    self._iconBg = ""
    self._combatType = {}
    self._skin = 0
