    self.maxHp = 0                --最大血量上限
    self._treeInfo = nil        -- 英雄觉醒技能树
    self._endTime = 0        -- 限时英雄，0表示永久
    self._isTry = false        -- 是否为限时英雄
    self._talentSkills = {}
    self._coreLevel = 0            -- 核心等级
    self._outfitSkill = 0
    self.sorceryCardId = 0
