function StructHero:CreateByPb(pb)
    self._combatType = {}
    self._pb = pb
    self._id = pb.id
    self._refId = pb.refId
    self._level = pb.level or pb.lv
    self._constLevel = self._level
    self._star = pb.star
    self._constStar = self._star
    self._grade = pb.grade
    self._fightPower = pb.fightPower
    self._lock = pb.lock
    self._isCombat = pb.isCombat
    self._nextRefId = pb.nextRefId
    self._isResonance = pb.isResonance
    self._constIsResonance = self._isResonance
    self._isLimitTime = pb.isLimitTime
    self._status = self:GetStatus()
    self._realLevel = pb.realLevel
    local struct = gModelHero:GetHeroStructById(self._id)
    if struct then
        local tempList = {}
        local combatTypeList = pb.combatType
        for i, v in ipairs(combatTypeList) do
            if v ~= 0 then
                table.insert(tempList, v)
            end
        end
        table.sort(tempList, function(refId1, refId2)
            --local ref1,ref2 = gModelBattle:GetCombatPlayCampRefByRefId(refId1),gModelBattle:GetCombatPlayCampRefByRefId(refId2)
            local ref1, ref2 = gModelFormation:GetCombatGameRef(refId1), gModelFormation:GetCombatGameRef(refId2)
            if nil == ref1 or nil == ref2 then
                if LOG_INFO_ENABLED then
                    printInfoNR2("CombatGameRef--缺少的配置--", "----" .. tostring(refId1) .. "---or ---" .. tostring(refId2))
                end
            else
                local sort1, sort2 = ref1.sort, ref2.sort
                return sort1 < sort2
            end
        end)
        self._combatType = tempList
    end
    self._skin = pb.skin
    self.hp = pb.hp
    self.maxHp = pb.maxHp

    local treeInfo = StructHeroTreeInfo:New()
    treeInfo:CreateByPb(pb.treeInfo)
    self._treeInfo = treeInfo
    self._endTime = 0
    if pb.endTime then
        self._endTime = tonumber(pb.endTime) / 1000
    end
    self._isTry = self._endTime and self._endTime > 0

    self._talentSkills = {}
    local talentSkills = pb.talentSkills or {}
    for i, v in ipairs(talentSkills) do

        if type(v) == "table" then
            local position = v.position
            local skillId = v.skillId
            self._talentSkills[position] = skillId
        end
    end
    self._coreLevel = pb.coreLevel

    self._outfitSkill = pb.outfitSkill
    self.sorceryCardId = pb.sorceryCardId
    self.spiritLinkId = pb.spiritLinkId
    self.sorceryCardLevel = pb.sorceryCardLevel
    -- self.crystalSheet = pb.crystalSheet【G公共支持】删除伙伴晶石功能相关数据
    self.name = pb.name
    --- 核心羁绊激活状态(1=已激活)
    self.fetters = pb.fetters or 0
    self.isFetters = self.fetters == StructHero.ACT_FETTERS
    if pb.form then
        if type(pb.form) == "number" then
            self.form = pb.form
            self.formTime = pb.formTime
        else
            self.form = pb.form.form
            self.formTime = pb.form.formTime
        end
    end
    self.loveValue = pb.loveValue or 0
    self.loveLevel = pb.loveLevel or 0
    self.petIds = {}
    if pb.petId then
        if  type(pb.petId) == "table" then
            for _, petId in ipairs(pb.petId) do
                table.insert(self.petIds,petId)
            end
        end
    end
end

