function StructHero:GetStatus()
    local lock, combat, resonance = self._lock, self._isCombat, self._isResonance
    local b = (lock == 0) and (combat == 0) and (resonance == 0)
    if b then
        -- 无状态
        return 0
    else
        return 1
    end
end

