function StructHero:GetTreePoints(jumpSort)
    if not self._treeInfo then
        return {}
    end

    local points = self._treeInfo.points
    if not points then
        return {}
    end

    if jumpSort then
        return points
    end

    local resultPoints = {}
    for k, v in ipairs(points) do
        local pointRefId = v.pointRefId
        resultPoints[pointRefId] = v
    end
    return resultPoints
end

